import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Download } from 'lucide-react';

export default function TransactionTable() {
  const theme = useTheme();

  const [transactions, setTransactions] = useState([
    {
      id: 1,
      date: '2024-03-15',
      description: 'Transaction 1',
      amount: '$100.00',
      status: 'success',
    },
    {
      id: 2,
      date: '2024-03-16',
      description: 'Transaction 2',
      amount: '-$50.00',
      status: 'pending',
    },
    {
      id: 3,
      date: '2024-03-17',
      description: 'Transaction 3',
      amount: '$200.00',
      status: 'success',
    },
  ]);

  useEffect(() => {
    // Add any necessary API call or data fetching logic here
  }, []);

  const handleDownloadCSV = () => {
    const csvContent = transactions.map((transaction) => {
      return `${transaction.date},${transaction.description},${transaction.amount},${transaction.status}`;
    }).join('
');

    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'transactions.csv';
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="max-w-7xl mx-auto pt-12 pb-10">
      <h2 className="text-2xl font-bold mb-4">Transaction History</h2>
      <div className="bg-zinc-600 rounded-md p-4 shadow-md">
        <div className="flex justify-between mb-4">
          <div className="text-zinc-400 font-bold">Date</div>
          <div className="text-zinc-400 font-bold">Description</div>
          <div className="text-zinc-400 font-bold">Amount</div>
          <div className="text-zinc-400 font-bold">Status</div>
        </div>
        <div className="overflow-x-auto">
          <table className="table-auto border-collapse border border-gray-100">
            <tbody>
              {transactions.map((transaction, index) => (
                <tr key={index} className="border-b border-gray-100 hover:bg-zinc-700">
                  <td className="py-4 pl-4">{transaction.date}</td>
                  <td className="py-4 pl-4">{transaction.description}</td>
                  <td className="py-4 pl-4 text-zinc-400">{transaction.amount}</td>
                  <td className="py-4 pl-4">{transaction.status}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <div className="flex justify-end mt-4">
          <button
            className="bg-zinc-600 hover:bg-zinc-700 text-zinc-400 font-bold py-2 px-4 rounded-md"
            onClick={handleDownloadCSV}
          >
            <Download className="mr-2" size={20} />Download CSV
          </button>
        </div>
      </div>
    </div>
  );
}

