import React, { useState, useEffect } from 'react';
import { Star, Quote } from 'lucide-react';
import { Link } from 'react-router-dom';

export default function TestimonialCarousel() {
  const [currentIndex, setCurrentIndex] = useState(0);
  const testimonials = [
    {
      name: 'John Doe',
      role: 'Founder at DataSphere',
      text: 'DataSphere is the most innovative solution I have ever used. It has greatly improved our data visualization and analysis capabilities.',
      rating: 5,
    },
    {
      name: 'Jane Doe',
      role: 'CEO at ABC Inc.',
      text: 'DataSphere has been a game-changer for our business. It has helped us make data-driven decisions and has improved our overall performance.',
      rating: 4.5,
    },
    {
      name: 'Bob Smith',
      role: 'CTO at DEF Corp.',
      text: 'DataSphere is an excellent tool for data analysis and visualization. It has helped us identify areas for improvement and has improved our overall efficiency.',
      rating: 4,
    },
  ];

  useEffect(() => {
    const intervalId = setInterval(() => {
      setCurrentIndex((prevIndex) => (prevIndex + 1) % testimonials.length);
    }, 5000);

    return () => clearInterval(intervalId);
  }, []);

  return (
    <div className="relative py-12 bg-zinc-600">
      <div className="container mx-auto px-4 sm:px-6 lg:px-12 py-16">
        <div className="text-center mb-8">
          <h2 className="text-3xl font-bold text-white">What our customers say</h2>
          <p className="text-lg text-zinc-400">Discover how DataSphere has helped businesses like yours</p>
        </div>
        <Carousel
          className="relative mb-12 lg:mb-0"
          buttonsProps={{
            className: 'absolute top-1/2 -translate-y-1/2',
          }}
          initialIndex={currentIndex}
        >
          {testimonials.map((testimonial, index) => (
            <CarouselItem key={index}>
              <div className="flex flex-col items-center">
                <div className="bg-zinc-700 rounded-md p-4 mb-4">
                  <Quote size={32} className="text-zinc-400" />
                  <p className="text-lg text-zinc-400">{testimonial.text}</p>
                </div>
                <div className="flex items-center justify-center">
                  {[...Array(testimonial.rating)].map((_, i) => (
                    <Star key={i} size={16} className="text-zinc-400" />
                  ))}
                </div>
                <p className="text-lg font-bold text-white">{testimonial.name}</p>
                <p className="text-lg text-zinc-400">{testimonial.role}</p>
              </div>
            </CarouselItem>
          ))}
        </Carousel>
        <div className="text-center">
          <Link to="/testimonials" className="text-lg text-zinc-400 hover:text-white transition duration-200">
            Read all testimonials
          </Link>
        </div>
      </div>
    </div>
  );
}

